queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?animalname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:animalID ?cg . ?child a :Animals ; p:animalID ?cg . ?l p:zooID ?pg . ?parent a :Zoo ; p:zooID ?pg . } GROUP BY ?child }
  ?child p:animalName ?animalname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Zoo } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?zooname ?animalname WHERE {
  ?zoo_animals a :Zoo_Animals .
  ?animals a :Animals .
  ?zoo_animals p:hasAnimals ?animals .
  ?zoo a :Zoo .
  ?zoo_animals p:hasZoo ?zoo .
  ?zoo p:zooName ?zooname .
  ?animals p:animalName ?animalname .
} }
  collective: { SELECT ?animalname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:animalID ?cg . ?child a :Animals ; p:animalID ?cg . ?l p:zooID ?pg . ?parent a :Zoo ; p:zooID ?pg . } GROUP BY ?child }
  ?child p:animalName ?animalname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Zoo } }
  FILTER(?nf = ?total)
} }
}
